import{_ as i,o as l,c as t,a2 as e}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"Date Picker 日期选择","description":"","frontmatter":{"title":"Date Picker 日期选择","stage":"intermediate","direction":"interaction-design","tags":["interaction-pattern","input","date-picker"]},"headers":[],"relativePath":"03-interaction-design/notes/06-interaction-patterns/01-input/date-picker.md","filePath":"03-interaction-design/notes/06-interaction-patterns/01-input/date-picker.md","lastUpdated":1784542968000}'),s={name:"03-interaction-design/notes/06-interaction-patterns/01-input/date-picker.md"};function n(r,a,h,d,o,p){return l(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="date-picker-日期选择" tabindex="-1">Date Picker 日期选择 <a class="header-anchor" href="#date-picker-日期选择" aria-label="Permalink to &quot;Date Picker 日期选择&quot;">​</a></h1><p>Date Picker 日期选择协调日期文本、日历网格、允许范围和日期语义。只有任务需要浏览相邻日期或选择范围时才需要弹出日历；已知日期的快速录入仍应保留可编辑文本路径。</p><h2 id="能力边界与前置知识" tabindex="-1">能力边界与前置知识 <a class="header-anchor" href="#能力边界与前置知识" aria-label="Permalink to &quot;能力边界与前置知识&quot;">​</a></h2><p>Date Picker 日期选择负责把用户输入转换为可校验、可提交、可恢复的数据。它不能替代服务端授权、业务校验、唯一约束、恶意内容处理或并发控制。</p><p>前置知识：</p><ul><li>能定义字段或文档的数据类型、必填、范围和业务不变量；</li><li>能区分原始输入、显示值、规范化值和稳定对象 ID；</li><li>了解表单标签、可访问名称、焦点顺序和状态消息；</li><li>能观察请求、响应、对象版本和权威写入结果。</li></ul><h2 id="组成部分" tabindex="-1">组成部分 <a class="header-anchor" href="#组成部分" aria-label="Permalink to &quot;组成部分&quot;">​</a></h2><ul><li>逻辑日期：不含时区的日历日。</li><li>时间点：需要时区或偏移才能唯一定位。</li><li>文本输入：允许直接键入和纠错。</li><li>日历网格：浏览临近日期与范围。</li><li>可用规则：最早、最晚、禁用日和服务端实时库存。</li></ul><p>输入文本、日历焦点、已选日期和业务时区是四个独立状态。合同必须说明值表示自然日、当地日期时间还是绝对时间点，否则日历看似选中同一天，跨时区保存后仍可能改变。</p><h2 id="输入数据生命周期" tabindex="-1">输入数据生命周期 <a class="header-anchor" href="#输入数据生命周期" aria-label="Permalink to &quot;输入数据生命周期&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R[&quot;原始输入&quot;] --&gt; C[&quot;客户端可快速检查&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; N[&quot;规范化或对象选择&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    N --&gt; D[&quot;本地草稿&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; S[&quot;服务端授权与业务校验&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; W[&quot;受控写入&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    W --&gt; E[&quot;结果、版本与审计&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; F[&quot;字段、全局、冲突或临时错误&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; D</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="原始输入" tabindex="-1">原始输入 <a class="header-anchor" href="#原始输入" aria-label="Permalink to &quot;原始输入&quot;">​</a></h3><p>文本输入保留用户键入的日期字符串，解析结果单独存放。<code>03/04/2026</code> 在不同地区含义不同，无法按当前 locale 确定时应要求澄清，而不是静默交换月日。</p><h3 id="规范化值" tabindex="-1">规范化值 <a class="header-anchor" href="#规范化值" aria-label="Permalink to &quot;规范化值&quot;">​</a></h3><p>自然日保存为日历日期；预约时间保存当地日期时间、IANA 时区和必要的偏移确认；绝对事件保存时间点。格式化只负责显示，不能把格式化字符串当权威值。</p><h3 id="草稿" tabindex="-1">草稿 <a class="header-anchor" href="#草稿" aria-label="Permalink to &quot;草稿&quot;">​</a></h3><p>范围选择草稿记录起点、候选终点和当前日历月份，尚未完成的范围不能提交。恢复预约草稿时重新取得可预约区间，因为节假日、容量和时区规则可能已经变化。</p><h3 id="权威结果" tabindex="-1">权威结果 <a class="header-anchor" href="#权威结果" aria-label="Permalink to &quot;权威结果&quot;">​</a></h3><p>服务端用当前时区规则和可用性再次验证日期范围，成功后返回规范日期、时区和预约版本。名额被占用时保留用户选择并显示新的可选日期，不能只清空控件。</p><h2 id="专属行为" tabindex="-1">专属行为 <a class="header-anchor" href="#专属行为" aria-label="Permalink to &quot;专属行为&quot;">​</a></h2><ul><li>原生 date 输入的提交值是 yyyy-mm-dd，显示由浏览器 locale 决定。</li><li>出生日期等远距离日期通常直接分字段或文本输入更高效。</li><li>自定义日历遵循 dialog/grid 键盘行为并提供月份导航。</li><li>日期范围明确包含端点、最大跨度和跨月规则。</li><li>客户端禁用日期仍需服务端重新验证可用性。</li></ul><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><ol><li>业务需要日期、当地时间还是绝对时间点。</li><li>时区取用户、对象地点还是组织设置。</li><li>日历是否真的优于已知日期输入。</li><li>DST 缺失或重复本地时间怎样处理。</li><li>格式解析是否拒绝歧义输入并保留原值。</li></ol><p>验收必须覆盖 locale、时区、夏令时缺失或重复时刻、键盘日历浏览、禁用日期和跨月范围，明确哪一种日期语义被保存。</p><h2 id="状态模型" tabindex="-1">状态模型 <a class="header-anchor" href="#状态模型" aria-label="Permalink to &quot;状态模型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>进入条件</th><th>界面责任</th><th>退出条件</th></tr></thead><tbody><tr><td>Date Picker 日期选择未触碰</td><td>还没有本次交互</td><td>显示标签、规则和合理默认值</td><td>用户输入或选择</td></tr><tr><td>编辑中</td><td>原始值正在变化</td><td>保持焦点和输入法行为</td><td>完成输入、取消或提交</td></tr><tr><td>本地无效</td><td>可确定格式或范围错误</td><td>就近说明修正方式</td><td>输入变为有效</td></tr><tr><td>可提交</td><td>本地条件满足</td><td>主操作可用，不承诺业务成功</td><td>提交、继续编辑</td></tr><tr><td>提交中</td><td>请求或上传进行</td><td>防重复意图，保留输入</td><td>成功、失败、超时、取消</td></tr><tr><td>日期被拒绝</td><td>名额、截止时间或允许范围已变化</td><td>保留输入，更新禁用日期并解释失效原因</td><td>选择新日期或取消</td></tr><tr><td>冲突</td><td>基础对象版本变化</td><td>比较、刷新或合并</td><td>新版本确认</td></tr><tr><td>预约结果未知</td><td>创建预约时请求超时</td><td>按预约意图 ID 查询，不重复占用同一时段</td><td>找到预约或恢复候选范围</td></tr><tr><td>成功</td><td>权威结果完成</td><td>显示结果和下一步</td><td>后续操作</td></tr></tbody></table><p>状态不能只存在于颜色。错误、等待、选中、进度和保存结果应有程序化表达。</p><h2 id="工程状态示例" tabindex="-1">工程状态示例 <a class="header-anchor" href="#工程状态示例" aria-label="Permalink to &quot;工程状态示例&quot;">​</a></h2><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;kind&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;date-range&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;startDate&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-18&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;endDate&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-07-25&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;timeZone&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Asia/Shanghai&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>示例字段不是通用接口标准。项目应按Date Picker 日期选择的真实值类型定义 schema，并明确缺失值、无效值、服务端错误、版本和恢复语义。</p><h2 id="校验顺序" tabindex="-1">校验顺序 <a class="header-anchor" href="#校验顺序" aria-label="Permalink to &quot;校验顺序&quot;">​</a></h2><ol><li>Date Picker 日期选择输入前说明格式、单位、范围和不可接受内容。</li><li>输入期间只做不会打断输入法的安全检查。</li><li>完成输入或离开字段后给出可修正反馈。</li><li>提交时客户端汇总当前已知错误。</li><li>服务端重新执行格式、授权、业务和并发校验。</li><li>返回字段错误与全局错误的稳定代码和安全文案。</li><li>界面保留合法输入，把焦点移到合理错误入口。</li><li>修正后只清除已经解决的错误。</li><li>成功后从权威响应更新对象和版本。</li></ol><p>客户端限制可以减少错误，不能防止直接请求、旧客户端或恶意输入。</p><h2 id="案例一-预约系统选择未来可用日期" tabindex="-1">案例一：预约系统选择未来可用日期 <a class="header-anchor" href="#案例一-预约系统选择未来可用日期" aria-label="Permalink to &quot;案例一：预约系统选择未来可用日期&quot;">​</a></h2><h3 id="固定输入" tabindex="-1">固定输入 <a class="header-anchor" href="#固定输入" aria-label="Permalink to &quot;固定输入&quot;">​</a></h3><ul><li>使用合成账户与合成业务数据；</li><li>正常网络 80 ms，另注入 2 秒延迟和一次 503；</li><li>打开时对象版本为 17，提交前另一个会话更新为 18；</li><li>覆盖空值、无效值、长值、重复值和权限撤销；</li><li>记录可见结果、焦点、请求、响应和权威对象。</li></ul><h3 id="设计与实现" tabindex="-1">设计与实现 <a class="header-anchor" href="#设计与实现" aria-label="Permalink to &quot;设计与实现&quot;">​</a></h3><ol><li>原生 date 输入的提交值是 yyyy-mm-dd，显示由浏览器 locale 决定。</li><li>出生日期等远距离日期通常直接分字段或文本输入更高效。</li><li>自定义日历遵循 dialog/grid 键盘行为并提供月份导航。</li><li>日期范围明确包含端点、最大跨度和跨月规则。</li><li>客户端禁用日期仍需服务端重新验证可用性。</li></ol><p>预约成功后使用服务端返回的预约 ID、当地日期时间、IANA 时区和显示偏移更新摘要；客户端解析出的暂定时间不能冒充最终预约。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>鼠标、键盘、触屏和屏幕阅读器都能完成；</li><li>输入法组合期间不误提交；</li><li>本地错误与服务端错误均能修正；</li><li>请求失败和冲突不清空合法工作；</li><li>重复触发只产生一个逻辑副作用；</li><li>最终显示与权威数据对账一致。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>本地午夜换算成 UTC 后落到前一天</p><p>修复后重复相同输入和时序，确认界面状态、服务端副作用和审计记录同时正确。</p><h2 id="案例二-报表选择跨月统计范围" tabindex="-1">案例二：报表选择跨月统计范围 <a class="header-anchor" href="#案例二-报表选择跨月统计范围" aria-label="Permalink to &quot;案例二：报表选择跨月统计范围&quot;">​</a></h2><h3 id="固定输入-1" tabindex="-1">固定输入 <a class="header-anchor" href="#固定输入-1" aria-label="Permalink to &quot;固定输入&quot;">​</a></h3><ul><li>360 CSS px 视口与 200% 文本缩放；</li><li>系统大字体、中文输入法和仅键盘操作；</li><li>网络先离线，恢复后响应超时；</li><li>会话在未提交工作存在时到期；</li><li>数据包含同名对象、过期引用和被删除目标。</li></ul><h3 id="设计过程" tabindex="-1">设计过程 <a class="header-anchor" href="#设计过程" aria-label="Permalink to &quot;设计过程&quot;">​</a></h3><ol><li>报表输入的是逻辑日期范围，不在客户端转换为 UTC 时间点。</li><li>文本框允许直接输入 yyyy-mm-dd，日历用于浏览临近日期。</li><li>范围包含起止日，最大 90 天，结束不得早于开始。</li><li>自定义日历使用 dialog 与 grid 键盘模型。</li><li>提交时服务端按报表时区生成精确时间边界。</li><li>DST 边界用该时区规则计算，不按固定 24 小时相乘。</li></ol><p>窄屏日历一次显示完整周列并保证日期按钮可读，月份切换、文本输入和错误不脱离控件。离线时允许保留候选日期，但所有可用性状态标为待刷新。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>关闭和恢复网络后不重复写入；</li><li>刷新后按声明的草稿策略恢复；</li><li>会话到期不把敏感值写入不安全存储；</li><li>失效引用有替换、清除或返回路径；</li><li>读屏能获知结果而无需焦点被强制移动；</li><li>长文本不会遮挡唯一保存或取消动作。</li></ul><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>会话在Date Picker 日期选择进行中到期。界面必须暂停后续写入，保留允许保留的非敏感工作，重新认证后再次校验权限与版本；不能直接重放旧请求。</p><p>会话恢复后保留用户输入的日期范围，重新加载时区规则和可预约区间；已失效日期在原位置标错，并提供最近合法日期，不能自动替换用户选择。</p><h2 id="无障碍实现" tabindex="-1">无障碍实现 <a class="header-anchor" href="#无障碍实现" aria-label="Permalink to &quot;无障碍实现&quot;">​</a></h2><h3 id="名称与说明" tabindex="-1">名称与说明 <a class="header-anchor" href="#名称与说明" aria-label="Permalink to &quot;名称与说明&quot;">​</a></h3><ul><li>Date Picker 日期选择的可见标签进入可访问名称。</li><li>帮助文本与错误通过程序化关系关联。</li><li>placeholder 不替代持久可见标签。</li><li>必填、单位、格式和限制不只靠颜色或图标。</li><li>复合输入使用与真实行为匹配的 APG 模式。</li></ul><h3 id="键盘与输入法" tabindex="-1">键盘与输入法 <a class="header-anchor" href="#键盘与输入法" aria-label="Permalink to &quot;键盘与输入法&quot;">​</a></h3><ul><li>Date Picker 日期选择的 Tab 顺序跟随 DOM 与视觉阅读顺序。</li><li>Enter、Space、方向键和 Escape 只按控件语义接管。</li><li>输入法 composition 期间不把中间文本当成完成值。</li><li>粘贴、语音输入和浏览器自动填充不被无理由阻止。</li><li>临时弹层关闭后焦点回到触发点或下一逻辑位置。</li><li>错误修正后焦点不被异步结果抢走。</li></ul><h3 id="重排" tabindex="-1">重排 <a class="header-anchor" href="#重排" aria-label="Permalink to &quot;重排&quot;">​</a></h3><p>在 320 CSS px 等效宽度和 200% 缩放下，七列日历仍显示完整日期名称，必要时使用更短但无歧义的星期标签；范围摘要和错误放在网格之外，避免覆盖日期按钮。</p><h2 id="安全、性能与一致性" tabindex="-1">安全、性能与一致性 <a class="header-anchor" href="#安全、性能与一致性" aria-label="Permalink to &quot;安全、性能与一致性&quot;">​</a></h2><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><ul><li>所有输入均视为不可信；</li><li>服务端重新授权和校验；</li><li>富文本与文件按输出上下文净化或隔离；</li><li>错误不泄露内部异常、受限对象或敏感路径；</li><li>日志不默认记录正文、文件内容、密码或令牌。</li></ul><h3 id="性能" tabindex="-1">性能 <a class="header-anchor" href="#性能" aria-label="Permalink to &quot;性能&quot;">​</a></h3><ul><li>取消失效查询并丢弃乱序响应；</li><li>长列表、长文档和大文件使用适合的分页、分片或后台任务；</li><li>加载优化不改变可访问树的完整语义；</li><li>缓存键包含租户、角色、语言和会改变结果的筛选条件；</li><li>性能预算覆盖输入响应、候选出现、提交和恢复。</li></ul><h3 id="一致性" tabindex="-1">一致性 <a class="header-anchor" href="#一致性" aria-label="Permalink to &quot;一致性&quot;">​</a></h3><ul><li>写请求带幂等或逻辑意图标识；</li><li>对现有对象修改带期望版本；</li><li>超时先查询结果而不是盲目重试；</li><li>部分成功返回逐项稳定 ID 与结果；</li><li>草稿与正式提交使用不同状态和权限；</li><li>客户端缓存不能静默覆盖服务端新版本。</li></ul><h2 id="调试与观测" tabindex="-1">调试与观测 <a class="header-anchor" href="#调试与观测" aria-label="Permalink to &quot;调试与观测&quot;">​</a></h2><ol><li>固定Date Picker 日期选择的输入、角色、对象版本、网络、语言和视口。</li><li>检查原始值、显示值、选择 ID、错误和焦点。</li><li>检查请求参数、取消、响应顺序和业务错误码。</li><li>检查服务端授权、规范化、版本和权威写入。</li><li>注入超时、权限撤销、并发和页面刷新。</li><li>用键盘、读屏、输入法和窄屏重复。</li></ol><p>观测指标：</p><ul><li>有效开始、提交、成功、失败、取消和恢复；</li><li>首次错误类型与最终修正率；</li><li>输入丢失和重复副作用；</li><li>候选或校验响应延迟；</li><li>键盘阻断、焦点丢失和错误未关联；</li><li>按平台、语言、角色和数据量分群的完成时间。</li></ul><h2 id="综合练习" tabindex="-1">综合练习 <a class="header-anchor" href="#综合练习" aria-label="Permalink to &quot;综合练习&quot;">​</a></h2><p>为Date Picker 日期选择完成可运行原型和服务端模拟。覆盖正常、无效、等待、失败、权限、过期、冲突、取消和未知结果。</p><p>验收：</p><ul><li>Date Picker 日期选择的数据类型、显示值、提交值和稳定 ID 边界明确；</li><li>两个案例有固定输入、处理、结果、验证和失败；</li><li>客户端与服务端校验责任分开；</li><li>失败后保留允许保留的工作；</li><li>键盘、屏幕阅读器和输入法完成任务；</li><li>弱网、窄屏和长文本不隐藏恢复；</li><li>日志与分析不收集不必要敏感内容；</li><li>权威数据与界面结果可以对账。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/WAI/ARIA/apg/patterns/dialog-modal/examples/datepicker-dialog/" target="_blank" rel="noreferrer">W3C WAI — Dialog Date Picker Example</a>（访问日期：2026-07-18）</li><li><a href="https://html.spec.whatwg.org/multipage/input.html#date-state-(type=date)" target="_blank" rel="noreferrer">WHATWG — Date state</a>（访问日期：2026-07-18）</li><li><a href="https://www.w3.org/TR/WCAG22/" target="_blank" rel="noreferrer">W3C — Web Content Accessibility Guidelines (WCAG) 2.2</a>（访问日期：2026-07-18）</li></ul>`,79)])])}const k=i(s,[["render",n]]);export{u as __pageData,k as default};
